import { IMessageComposer } from '@nitrots/nitro-renderer';

export class BlackJackJoinComposer implements IMessageComposer<unknown[]> {
    // optional: pass a specific table id, else let server seat you
    constructor(private _tableId: number | null = null) {}
    public getMessageArray() {
        return [this._tableId ?? 0];
    }
    public dispose(): void {}
    public get disposed(): boolean {
        return false;
    }
}
